import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  系统状态: z.object({
    当前世界: z.coerce.string().prefault('待初始化'),
    当前任务: z.coerce.string().prefault('待下发'),
    任务倒计时: z.coerce.string().prefault('待初始化'),
    主神债务: z.coerce.number().prefault(0),
  }),

  轮回者面板: z.object({
    等级与经验: z.object({
      当前等级: z.coerce.number().prefault(1),
      当前XP: z.coerce.number().prefault(0),
      升级阈值: z.coerce.number().prefault(300),
      可用属性点: z.coerce.number().prefault(0),
    }),
    基础六维: z.object({
      体质: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
      敏捷: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
      力量: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
      精神: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
      感知: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
      魅力: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(10),
    }),
    生存指标: z.object({
      生命值: z.object({
        当前HP: z.coerce.number().prefault(100),
        最大HP: z.coerce.number().prefault(100),
      }),
      理智值: z.coerce.number().prefault(20),
      压力值: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(0),
    }),
    资源: z.object({
      当前积分: z.coerce.number().prefault(0),
    }),
    装备栏: z.object({
      主手武器: z.coerce.string().prefault('空'),
      副手盾牌: z.coerce.string().prefault('空'),
      身体防具: z.coerce.string().prefault('初始衣物'),
      饰品: z.coerce.string().prefault('空'),
    }),
    物品栏: z.object({
      已持有道具: z.coerce.string().prefault('空'),
    }),
  }),

  契约从者: z.record(
    z.object({
      状态: z.coerce.string().prefault('健康'),
      好感度: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(0),
      依存度: z.coerce.number().transform(v => Math.min(Math.max(v, 0), 100)).prefault(0),
      特殊羁绊: z.coerce.string().prefault('无'),
    })
  ).prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
});

