            { id: "Cyberpunk", name: "赛博朋克2077 (夜之城)", desc: "目标：夜之城。传送门里传出了重金属电子乐和枪声。" },
            { id: "ResidentEvil", name: "生化危机 (浣熊市)", desc: "目标：浣熊市。去往该位面的传送门散发着刺鼻的福尔马林气味。" },
            { id: "EldenRing", name: "艾尔登法环 (交界地)", desc: "目标：交界地。这是一次极度危险的单程票，主神正将法则转化为暗黑魔法模式。" }
        ],
        movie: [
            { id: "Marvel", name: "漫威宇宙 (纽约之战)", desc: "目标：漫威宇宙。主神广场上方正投影着齐塔瑞大军入侵纽约的画面。" },
