    function submitCreation() {
        const realname = document.getElementById('user-realname').value.trim() || '无名氏';
        const job = document.getElementById('user-job').value;
        const faction = document.getElementById('user-faction').value;
        const cat = document.getElementById('world-category').value;

        let worldName = "";

        if (cat === 'custom') {
            worldName = document.getElementById('user-world-custom').value.trim() || "未知世界";
        } else {
            const worldId = document.getElementById('user-world').value;
            worldName = worldDB[cat].find(w => w.id === worldId).name;
        }

        let factionPrompt = "";
        switch(faction) {
            case "散人": factionPrompt = "我作为拒绝任何阵营邀请的【散人】醒来。周围没有同伴，只有主神冰冷的机械音。"; break;
            case "天启联盟": factionPrompt = "我作为【天启联盟】的外围新人醒来。一名资深者站在我面前，告诉我马上就要被传送了。"; break;
            case "血月会": factionPrompt = "我降临在主神广场的【血月会】聚集区。周围的新人正警惕地互相打量。"; break;
            case "极乐伊甸": factionPrompt = "我在极乐伊甸的地下室醒来，身上已经被打上了欠债标记。债主伊芙琳（冷酷的魅魔）拿着契约让我签字。"; break;
        }

        let stats = { str:10, dex:10, con:10, int:10, per:10, cha:10 };
        if(job === "医护人员") { stats = { str:9, dex:10, con:10, int:12, per:12, cha:9 }; }
        else if(job === "退役军人") { stats = { str:12, dex:11, con:12, int:9, per:10, cha:8 }; }
        else if(job === "法外狂徒") { stats = { str:11, dex:12, con:11, int:9, per:11, cha:8 }; }
        else if(job === "极客/黑客") { stats = { str:8, dex:10, con:9, int:14, per:11, cha:8 }; }

        const message = `【系统指令：完成建档与生成开场】\n我是：${realname}，原身份：${job}。\n\n[KP系统提示：不要向我打招呼，不要复述设定。立刻以第二人称（你）的视角，为我生成硬核跑团的开场剧情！]\n[环境强制要求：我的出生点在**主神空间的中央广场（大光球下方）**，或者是阵营的专属区域。不要让我直接面对怪物！]\n[主线目标：主神即将把我传送到任务世界【${worldName}】。当前正处于传送倒计时（3分钟）。]\n[阵营处境：${factionPrompt}]\n\n[强制机制：必须在回复末尾原样输出下方代码以初始化机体，禁止删减！]\n<UpdateVariable>\n<Analysis>Init stats</Analysis>\n<JSONPatch>\n[\n  { "op": "replace", "path": "/系统状态/当前世界", "value": "主神空间" },\n  { "op": "replace", "path": "/系统状态/当前任务", "value": "等待传送至：${worldName}" },\n  { "op": "replace", "path": "/系统状态/任务倒计时", "value": "03:00" },\n  { "op": "replace", "path": "/轮回者面板/基础六维/力量", "value": ${stats.str} },\n  { "op": "replace", "path": "/轮回者面板/基础六维/敏捷", "value": ${stats.dex} },\n  { "op": "replace", "path": "/轮回者面板/基础六维/体质", "value": ${stats.con} },\n  { "op": "replace", "path": "/轮回者面板/基础六维/精神", "value": ${stats.int} },\n  { "op": "replace", "path": "/轮回者面板/基础六维/感知", "value": ${stats.per} },\n  { "op": "replace", "path": "/轮回者面板/基础六维/魅力", "value": ${stats.cha} }\n]\n</JSONPatch>\n</UpdateVariable>\n\n[要求：保持绝对零度文风，客观描写主神空间的压抑感和传送前的准备。剧情写完后生成<Action_Options>供我选择传送前的行为。开始！]`;

        document.getElementById('loading-overlay').style.display = 'flex';

        try {
            const input = window.parent.document.querySelector('#send_textarea');
            if (input) {
                input.value = message;
                input.dispatchEvent(new Event('input', { bubbles: true }));
                setTimeout(() => {
                    const sendBtn = window.parent.document.querySelector('#send_but');
                    if (sendBtn) sendBtn.click();
                    setTimeout(() => { document.getElementById('creation-box').style.display = 'none'; }, 300);
                }, 800);
            }
        } catch (error) {
            console.error('发送失败:', error);
            document.getElementById('loading-overlay').style.display = 'none';
        }
    }

    window.onload = () => { populateWorlds(); };
</script>

</body>
</html>
