    <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" rel="stylesheet">
    <style>
        :root {
            --god-red: #ff2a2a; --god-red-glow: rgba(255, 42, 42, 0.6);
            --neon-cyan: #00f0ff; --neon-cyan-glow: rgba(0, 240, 255, 0.5);
            --bg-dark: rgba(8, 8, 12, 0.95);
            --text-main: #e0e0e0; --text-dim: #707080;
            --warning-yellow: #ffcc00; --danger-purple: #b366ff;
            --exp-green: #00ff66; --love-pink: #ff66b3;
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { margin: 0; padding: 0; }

        .god-space-terminal {
            font-family: 'Consolas', 'Courier New', monospace; background: var(--bg-dark); color: var(--text-main);
            border: 1px solid #222; border-top: 3px solid var(--god-red); border-radius: 6px;
            padding: 16px; margin: 10px 0; box-shadow: 0 10px 30px rgba(0, 0, 0, 0.8), inset 0 0 20px rgba(255, 42, 42, 0.1);
            max-width: 600px; position: relative; overflow: hidden; z-index: 1;
        }
        .god-space-terminal::before {
            content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 100px;
            background: linear-gradient(0deg, rgba(0, 240, 255, 0.05) 0%, transparent 100%);
            background-size: 100% 20px; background-image: repeating-linear-gradient(0deg, transparent, transparent 19px, rgba(0, 240, 255, 0.1) 20px);
            animation: grid-scroll 3s linear infinite; z-index: -1; pointer-events: none;
        }
        @keyframes grid-scroll { 0% { transform: translateY(0); } 100% { transform: translateY(20px); } }

        .terminal-header {
            display: flex; justify-content: space-between; align-items: center;
            border-bottom: 1px solid var(--god-red); padding-bottom: 8px; margin-bottom: 12px;
            font-size: 1.1em; font-weight: bold; color: var(--god-red); text-transform: uppercase; letter-spacing: 2px; text-shadow: 0 0 8px var(--god-red-glow);
        }
        .status-indicator { font-size: 0.7em; color: var(--neon-cyan); border: 1px solid var(--neon-cyan); padding: 2px 8px; border-radius: 12px; box-shadow: 0 0 10px var(--neon-cyan-glow); animation: pulse-sync 2s infinite; }
        @keyframes pulse-sync { 0%, 100% { opacity: 1; box-shadow: 0 0 10px var(--neon-cyan-glow); } 50% { opacity: 0.4; box-shadow: 0 0 2px transparent; } }

        /* ======== 音乐播放器 & 字幕模块 ======== */
        .audio-player-wrapper {
            background: rgba(0, 0, 0, 0.6); border: 1px solid #333; border-left: 3px solid var(--neon-cyan);
            border-radius: 4px; margin-bottom: 12px; box-shadow: inset 0 0 10px rgba(0,0,0,0.5);
            display: flex; flex-direction: column; overflow: hidden;
        }
        .audio-player-main { display: flex; align-items: center; justify-content: space-between; padding: 6px 10px; }
        .audio-info { font-size: 0.75em; color: var(--neon-cyan); display: flex; align-items: center; gap: 8px; font-family: monospace; letter-spacing: 1px; }
        .audio-controls { display: flex; align-items: center; gap: 10px; }
        .audio-btn { background: transparent; border: none; color: #fff; cursor: pointer; transition: color 0.3s; text-shadow: 0 0 5px rgba(255,255,255,0.5); outline: none; }
        .audio-btn:hover { color: var(--neon-cyan); text-shadow: 0 0 8px var(--neon-cyan-glow); }
        .volume-slider { width: 60px; height: 4px; -webkit-appearance: none; background: #333; outline: none; border-radius: 2px; }
        .volume-slider::-webkit-slider-thumb { -webkit-appearance: none; width: 10px; height: 10px; background: var(--neon-cyan); border-radius: 50%; cursor: pointer; box-shadow: 0 0 5px var(--neon-cyan-glow); }
        .playing-animation { display: flex; gap: 2px; height: 10px; align-items: flex-end; }
        .bar { width: 3px; background: var(--neon-cyan); animation: bounce 0.5s infinite alternate; }
        .bar:nth-child(2) { animation-delay: 0.1s; } .bar:nth-child(3) { animation-delay: 0.2s; } .bar:nth-child(4) { animation-delay: 0.3s; }
        @keyframes bounce { 0% { height: 2px; } 100% { height: 10px; } }
        .paused .bar { animation: none; height: 2px !important; }
        .lyrics-bar {
            background: rgba(0, 240, 255, 0.05); border-top: 1px dashed #333; padding: 4px 10px;
            font-size: 0.75em; color: #fff; font-family: 'Consolas', monospace; text-align: center; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; min-height: 24px; position: relative;
        }
        .lyrics-bar::before { content: 'LYRICS // '; color: var(--text-dim); font-size: 0.9em; margin-right: 5px; }
        .lyrics-text { text-shadow: 0 0 5px rgba(255,255,255,0.4); transition: opacity 0.3s; }
        .lyrics-text.glitch { animation: lyrics-glitch 0.2s; color: var(--neon-cyan); text-shadow: 0 0 8px var(--neon-cyan-glow); }
        @keyframes lyrics-glitch { 0% { transform: translate(2px, 1px); } 50% { transform: translate(-2px, -1px); } 100% { transform: translate(0, 0); } }

        /* ====== 全息导航栏 ====== */
        .tab-nav { display: flex; margin-bottom: 15px; background: rgba(0,0,0,0.5); border-radius: 4px; padding: 2px; border: 1px solid #333;}
        .tab-btn { flex: 1; background: transparent; border: none; padding: 6px 0; color: var(--text-dim); cursor: pointer; font-family: inherit; font-size: 0.8em; font-weight: bold; letter-spacing: 1px; transition: all 0.3s; border-radius: 3px; }
        .tab-btn:hover { color: #fff; text-shadow: 0 0 8px rgba(255,255,255,0.5); }
        .tab-btn.active { color: var(--neon-cyan); background: rgba(0, 240, 255, 0.1); box-shadow: inset 0 0 10px rgba(0, 240, 255, 0.2); text-shadow: 0 0 5px var(--neon-cyan-glow); border-bottom: 2px solid var(--neon-cyan);}
        .tab-content { display: none; animation: slideUpFade 0.3s ease forwards; }
        .tab-content.active { display: block; }
        @keyframes slideUpFade { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }

        .section-title { font-size: 0.85em; color: #fff; margin: 8px 0; border-left: 3px solid var(--neon-cyan); padding-left: 8px; background: linear-gradient(90deg, rgba(0, 240, 255, 0.15) 0%, transparent 100%); letter-spacing: 1px; display: flex; justify-content: space-between; align-items: center; }
        .grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(130px, 1fr)); gap: 8px; margin-bottom: 12px; }
        .data-box { background: rgba(0, 0, 0, 0.6); border: 1px solid #333; border-radius: 4px; padding: 8px; display: flex; flex-direction: column; transition: all 0.3s; }
        .data-label { font-size: 0.7em; color: var(--text-dim); margin-bottom: 4px; display: flex; align-items: center; gap: 5px; text-transform: uppercase;}
        .data-label i { color: var(--neon-cyan); }
        .data-value { font-size: 1.1em; color: #fff; font-weight: bold; font-family: monospace; }
        .value-warning { color: var(--god-red); text-shadow: 0 0 5px var(--god-red-glow); animation: blink-danger 1.5s infinite; }
        .value-gold { color: var(--warning-yellow); text-shadow: 0 0 5px rgba(255,204,0,0.5); }
        @keyframes blink-danger { 0%, 100% { opacity: 1; } 50% { opacity: 0.7; } }

        .mission-box { background: linear-gradient(90deg, rgba(0,240,255,0.05), transparent); border: 1px dashed var(--neon-cyan); border-left: 3px solid var(--neon-cyan); border-radius: 4px; padding: 8px; margin-bottom: 8px; display: flex; flex-direction: column; gap: 4px; }
        .mission-label { font-size: 0.7em; color: var(--neon-cyan); font-weight: bold; letter-spacing: 1px; }
        .mission-content { font-size: 0.85em; color: #fff; line-height: 1.4; word-break: break-all; }

        .progress-bar { background: #111; height: 6px; border-radius: 3px; overflow: hidden; margin-top: 5px; border: 1px solid #333; width: 100%; }
        .progress-fill { height: 100%; transition: width 0.3s; background-size: 15px 15px; background-image: linear-gradient(45deg, rgba(255,255,255,.15) 25%, transparent 25%, transparent 50%, rgba(255,255,255,.15) 50%, rgba(255,255,255,.15) 75%, transparent 75%, transparent); animation: stripe-move 1s linear infinite; }
        .progress-fill.hp { background-color: var(--god-red); box-shadow: 0 0 10px var(--god-red-glow); }
        .progress-fill.san { background-color: var(--neon-cyan); box-shadow: 0 0 10px var(--neon-cyan-glow); }
        .progress-fill.exp { background-color: var(--exp-green); box-shadow: 0 0 10px rgba(0, 255, 102, 0.5); }
        .progress-fill.love { background-color: var(--love-pink); box-shadow: 0 0 10px rgba(255, 102, 179, 0.5); background-image: linear-gradient(45deg, rgba(255,255,255,.2) 25%, transparent 25%, transparent 50%, rgba(255,255,255,.2) 50%, rgba(255,255,255,.2) 75%, transparent 75%, transparent); }
        @keyframes stripe-move { 0% { background-position: 0 0; } 100% { background-position: 15px 0; } }

        .attr-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 4px; margin-bottom: 8px; background: rgba(0, 0, 0, 0.4); border: 1px solid #333; padding: 6px; border-radius: 4px; }
        .attr-item { display: flex; justify-content: space-between; align-items: center; font-size: 0.85em; padding: 4px; background: rgba(255, 255, 255, 0.03); border-radius: 2px; }
        .attr-name { color: var(--text-dim); flex: 1; }
        .attr-num { color: #fff; font-weight: bold; font-size: 1.1em; text-align: right; width: 25px; }
        .attr-mod { color: var(--neon-cyan); font-size: 0.85em; text-align: right; width: 30px; border-left: 1px solid #444; margin-left: 4px; padding-left: 4px; font-family: monospace;}
        .attr-mod.negative { color: var(--god-red); }

        .equip-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; margin-bottom: 12px; }
        .equip-item { background: linear-gradient(135deg, rgba(20,20,25,0.8), rgba(5,5,10,0.8)); border: 1px solid #333; border-left: 2px solid #555; border-radius: 3px; padding: 6px 10px; display: flex; flex-direction: column; }
        .equip-item.active { border-left-color: var(--warning-yellow); background: rgba(255, 204, 0, 0.05); }
        .equip-label { font-size: 0.65em; color: var(--text-dim); text-transform: uppercase; margin-bottom: 2px; }
        .equip-val { font-size: 0.8em; color: #ddd; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

        .scroll-list { max-height: 250px; overflow-y: auto; padding-right: 4px; }
        .scroll-list::-webkit-scrollbar { width: 4px; }
        .scroll-list::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); }
        .scroll-list::-webkit-scrollbar-thumb { background: var(--danger-purple); border-radius: 2px; }

        .contract-card { background: linear-gradient(90deg, rgba(30,15,25,0.8), rgba(15,10,15,0.8)); border: 1px solid #444; border-left: 3px solid var(--love-pink); border-radius: 4px; padding: 8px; margin-bottom: 8px; transition: transform 0.2s; }
        .contract-card:hover { transform: translateX(3px); border-color: var(--love-pink); box-shadow: 0 0 10px rgba(255, 102, 179, 0.2); }
        .npc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px; }
        .npc-name { font-weight: bold; font-size: 0.9em; color: #fff; letter-spacing: 1px;}
        .npc-status { font-size: 0.7em; padding: 1px 6px; border-radius: 10px; border: 1px solid; background: rgba(0,0,0,0.5); }
        .npc-stats { display: flex; gap: 10px; margin-bottom: 6px; }
        .npc-stat-item { flex: 1; background: rgba(0,0,0,0.4); padding: 4px; border-radius: 3px; display: flex; flex-direction: column; align-items: center; border: 1px solid rgba(255,255,255,0.05);}
        .n-label { font-size: 0.65em; color: var(--text-dim); margin-bottom: 2px;}
        .n-val { font-size: 0.8em; font-weight: bold; color: #ddd;}

        /* ==== 优劣势系统样式 ==== */
        .adv-toggle { display: flex; gap: 6px; margin-bottom: 10px; }
        .adv-toggle input[type="radio"] { display: none; }
        .adv-btn { flex: 1; text-align: center; padding: 6px 0; font-size: 0.75em; font-weight: bold; border: 1px solid #444; border-radius: 4px; cursor: pointer; color: var(--text-dim); transition: all 0.2s; background: rgba(0,0,0,0.6); letter-spacing: 1px; }
        input[value="dis"]:checked + .adv-btn { border-color: #707080; background: rgba(112, 112, 128, 0.2); color: #fff; box-shadow: inset 0 0 8px rgba(255,255,255,0.1);}
        input[value="norm"]:checked + .adv-btn { border-color: var(--neon-cyan); background: rgba(0, 240, 255, 0.15); color: var(--neon-cyan); box-shadow: inset 0 0 8px rgba(0,240,255,0.2);}
        input[value="adv"]:checked + .adv-btn { border-color: var(--warning-yellow); background: rgba(255, 204, 0, 0.15); color: var(--warning-yellow); box-shadow: inset 0 0 8px rgba(255,204,0,0.2);}

        .fate-inputs { display: flex; gap: 6px; margin-bottom: 10px; }
        .dice-input { flex: 2; padding: 8px; background: rgba(0,0,0,0.6); border: 1px solid #444; color: var(--neon-cyan); border-radius: 4px; font-family: inherit; font-size: 12px; }
        .dice-input:focus { outline: none; border-color: var(--neon-cyan); }
        .mod-input, .diff-input { flex: 1; min-width: 40px; text-align: center; padding: 8px; background: rgba(0,0,0,0.6); border-radius: 4px; font-family: monospace; font-size: 12px; }
        .mod-input { border: 1px solid var(--neon-cyan); color: var(--neon-cyan); }
        .diff-input { border: 1px solid var(--god-red); color: var(--god-red); font-weight: bold; }
        .roll-btn { width: 100%; padding: 10px; background: linear-gradient(135deg, #4d0000, #990000); border: 1px solid var(--god-red); color: #fff; font-weight: bold; letter-spacing: 2px; border-radius: 4px; cursor: pointer; transition: all 0.2s; }
        .roll-btn:hover:not(:disabled) { background: linear-gradient(135deg, #660000, #cc0000); box-shadow: 0 0 15px var(--god-red-glow); }

        .dice-display { position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.95); display: flex; flex-direction: column; align-items: center; justify-content: center; font-weight: bold; color: var(--warning-yellow); opacity: 0; pointer-events: none; transition: opacity 0.2s; z-index: 10;}
        .dice-display.active { opacity: 1; pointer-events: auto; }
        .dice-number { font-size: 36px; text-shadow: 0 0 10px var(--warning-yellow); font-family: monospace; line-height: 1; }
        .dice-detail { font-size: 0.7em; color: #888; margin-top: 6px; height: 12px; letter-spacing: 1px;}

        .system-toast { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); background: rgba(255, 42, 42, 0.9); color: #fff; padding: 10px 20px; border: 1px solid #fff; border-radius: 4px; font-weight: bold; font-size: 14px; opacity: 0; pointer-events: none; transition: opacity 0.3s; z-index: 100; box-shadow: 0 0 20px rgba(255, 42, 42, 0.8); }
        .system-toast.show { opacity: 1; }
    </style>
    <script type="module">
        function initAudioPlayer() {
            const audio = document.getElementById('bg-music');
            const playBtn = document.getElementById('play-pause-btn');
            const volSlider = document.getElementById('volume-slider');
            const anim = document.getElementById('audio-anim');
            const lyricsDisplay = document.getElementById('lyrics-text');
            let isPlaying = false;
            const rawLrc = `[00:00.00] [Intro]\n[00:15.08] 白瓷砖上映出支离破碎的晨曦\n[00:22.11] 那个悬浮的巨大瞳孔正倒计时\n[00:29.13] 呼吸里渗进一种金属质感的寒气\n[00:36.06] 时空的缝隙在足下裂开万丈深渊\n[00:43.08] 第一场落雪掩盖了泥沼里的脚印\n[00:46.25] 古堡里回荡着风铃破碎的叮咛\n[00:50.14] 命运被装进一枚透明的玻璃瓶\n[00:53.28] 抛向那无边无际却又漆黑的幻境\n[00:59.00] 没有一张地图标明归途的轨迹\n[01:02.17] 只有掌心里的纹路正变得清晰\n[01:05.28] 如果这是场不能中途退出的博弈\n[01:09.19] 我必须在黎明之前学会如何呼吸\n[01:14.11] 在无止尽的轮回里寻找一丝生机\n[01:21.13] 穿梭于硝烟弥漫和荒芜的废墟\n[01:27.20] 若不将那些未知的枷锁逐一拆去\n[01:35.02] 姓名终会被抹除在寂静的空隙\n[01:56.19] 残破的旗帜在地平线上孤独摇曳\n[02:03.23] 耳畔响起了不知名荒原的告诫\n[02:10.23] 每一个关卡都布满危险的细节\n[02:17.13] 稍有退缩便会坠入永恒的凛冽\n[02:25.17] 没有一个名字值得被刻在墓碑\n[02:29.16] 只有求生的本能还在血管突围\n[02:33.08] 既然这剧场谢幕前谁都不能回归\n[02:36.18] 那就用这身伤口当作勋章去追\n[02:41.14] 在无止尽的轮回里寻找一丝生机\n[02:48.19] 穿梭于硝烟弥漫和荒芜的废墟\n[02:54.24] 若不将那些未知的枷锁逐一拆去\n[03:02.06] 姓名终会被抹除在寂静的空隙\n[03:10.23] [Outro]`;
            const parseLrc = (lrcStr) => {
                const result = [];
                const timeReg = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;
                for (let line of lrcStr.split('\n')) {
                    const match = timeReg.exec(line);
                    if (match) {
                        const m = parseInt(match[1]); const s = parseInt(match[2]); const ms = parseInt(match[3].length === 2 ? match[3]+'0' : match[3]);
                        const time = m * 60 + s + ms / 1000;
                        const text = line.replace(timeReg, '').trim();
                        if(text) result.push({ time, text });
                    }
                }
                return result;
            };
            const parsedLyrics = parseLrc(rawLrc);
            let currentLineIndex = -1;
            audio.volume = 0.3;

            playBtn.addEventListener('click', () => {
                if (isPlaying) { audio.pause(); playBtn.innerHTML = '<i class="fas fa-play"></i>'; anim.classList.add('paused'); }
                else { audio.play().catch(e=>console.log(e)); playBtn.innerHTML = '<i class="fas fa-pause"></i>'; anim.classList.remove('paused'); }
                isPlaying = !isPlaying;
            });
            volSlider.addEventListener('input', (e) => { audio.volume = e.target.value; });
            audio.addEventListener('timeupdate', () => {
                if(!parsedLyrics.length) return;
                let newIndex = -1;
                for (let i = 0; i < parsedLyrics.length; i++) {
                    if (audio.currentTime >= parsedLyrics[i].time) newIndex = i; else break;
                }
                if (newIndex !== -1 && newIndex !== currentLineIndex) {
                    currentLineIndex = newIndex; lyricsDisplay.textContent = parsedLyrics[newIndex].text;
                    lyricsDisplay.classList.remove('glitch'); void lyricsDisplay.offsetWidth; lyricsDisplay.classList.add('glitch');
                }
            });
            audio.addEventListener('ended', () => {
                currentLineIndex = -1; lyricsDisplay.textContent = "WAITING FOR SIGNAL...";
                playBtn.innerHTML = '<i class="fas fa-play"></i>'; anim.classList.add('paused'); isPlaying = false;
            });
        }

        function populateCharacterData() {
            const V = getAllVariables();
            const getV = (path, def) => _.get(V, 'stat_data.' + path, def);

            $('#sys-world').text(getV('系统状态.当前世界', '待初始化'));
            $('#sys-task').text(getV('系统状态.当前任务', '待下发'));
            $('#sys-countdown').text(getV('系统状态.任务倒计时', '待初始化'));
            $('#sys-debt').text(getV('系统状态.主神债务', 0));
            // 顶部常驻栏积分更新
            $('#res-points-top').text(getV('轮回者面板.资源.当前积分', 0));

            const lv = getV('轮回者面板.等级与经验.当前等级', 1);
            const curXp = getV('轮回者面板.等级与经验.当前XP', 0);
            const maxXp = getV('轮回者面板.等级与经验.升级阈值', 300);
            $('#user-level').text(lv); $('#exp-current').text(curXp); $('#exp-max').text(maxXp);
            $('#exp-bar').css('width', (maxXp > 0 ? Math.min(100, (curXp / maxXp) * 100) : 0) + '%');

            ['体质', '敏捷', '力量', '精神', '感知', '魅力'].forEach((attr, i) => {
                const ids = ['con', 'dex', 'str', 'int', 'per', 'cha'];
                const attrVal = getV(`轮回者面板.基础六维.${attr}`, 10);
                const modVal = Math.floor((attrVal - 10) / 2);
                $(`#attr-${ids[i]}`).text(attrVal);
                $(`#mod-${ids[i]}`).text(modVal >= 0 ? `+${modVal}` : `${modVal}`).toggleClass('negative', modVal < 0);
            });

            const hpCur = getV('轮回者面板.生存指标.生命值.当前HP', 100);
            const hpMax = getV('轮回者面板.生存指标.生命值.最大HP', 100);
            $('#hp-current').text(hpCur); $('#hp-max').text(hpMax);
            $('#hp-bar').css('width', (hpMax > 0 ? Math.max(0, Math.min(100, (hpCur / hpMax) * 100)) : 0) + '%');

            const sanCur = getV('轮回者面板.生存指标.理智值', 20);
            $('#san-value').text(sanCur); $('#san-bar').css('width', Math.min(100, (sanCur / 100) * 100) + '%');
            $('#stress-value').text(getV('轮回者面板.生存指标.压力值', 0));

            // 武装分页里就不再显示大积分框了，因为提到上面了
            $('#inv-items').text(getV('轮回者面板.物品栏.已持有道具', '空'));

            const eqMain = getV('轮回者面板.装备栏.主手武器', '空');
            const eqOff = getV('轮回者面板.装备栏.副手盾牌', '空');
            const eqBody = getV('轮回者面板.装备栏.身体防具', '初始衣物');
            const eqAcc = getV('轮回者面板.装备栏.饰品', '空');
            $('#eq-main').text(eqMain); $('#eq-off').text(eqOff);
            $('#eq-body').text(eqBody); $('#eq-acc').text(eqAcc);

            $('.equip-item').removeClass('active');
            if(eqMain !== '空') $('#eq-main').parent().addClass('active');
            if(eqOff !== '空') $('#eq-off').parent().addClass('active');
            if(eqBody !== '空' && eqBody !== '初始衣物') $('#eq-body').parent().addClass('active');
            if(eqAcc !== '空') $('#eq-acc').parent().addClass('active');

            const contracts = getV('契约从者', {});
            const $cList = $('#contract-list');
            $cList.empty();
            const contractEntries = Object.entries(contracts);
            $('#contract-count').text(contractEntries.length);

            if (contractEntries.length === 0) {
                $cList.html('<div style="text-align:center;color:#555;padding:20px;letter-spacing:1px;font-size:0.8em; border: 1px dashed #333;">[ 资料库无响应：当前未检测到灵魂契约实体 ]</div>');
            } else {
                let html = '';
                contractEntries.forEach(([name, data]) => {
                    let statusColor = data.状态 === '健康' ? '#00ff66' : (data.状态 === '虚弱' ? '#ffcc00' : '#ff2a2a');
                    let love = data.好感度 || 0;

                    html += `
                    <div class="contract-card">
                        <div class="npc-header">
