                        </div>
                        <div style="font-size: 0.7em; color: var(--text-dim); margin-bottom: 2px;">好感度 / 服从度: <span style="color:var(--love-pink); float:right;">${love}%</span></div>
                        <div class="progress-bar" style="height: 4px; margin-top: 0; margin-bottom: 8px; background: rgba(255,102,179,0.1); border-color: rgba(255,102,179,0.2);">
                            <div class="progress-fill love" style="width:${love}%"></div>
                        </div>
                        <div class="npc-stats">
                            <div class="npc-stat-item"><span class="n-label">依存度</span><span class="n-val" style="color:var(--danger-purple)">${data.依存度 || 0}%</span></div>
                            <div class="npc-stat-item" style="flex:2;"><span class="n-label">特质/羁绊</span><span class="n-val">${data.特殊羁绊 || '无'}</span></div>
                        </div>
                    </div>`;
                });
                $cList.append(html);
            }
        }

        window.rollDice = function() {
            const action = $('#dice-action').val().trim();
            let mod = parseInt($('#dice-mod').val()), diff = parseInt($('#dice-diff').val());
            if (!action) { $('#sys-toast').text('警告：未检测到行动意图').addClass('show'); setTimeout(()=>$('#sys-toast').removeClass('show'), 1500); return; }
            if (isNaN(mod)) mod = 0; if (isNaN(diff) || diff < 1) diff = 15;

            const rollType = $('input[name="roll-type"]:checked').val();
            $('#roll-btn').prop('disabled', true);
            $('#dice-display').addClass('active');
            $('#roll-detail').text('');

            let ticks = 0;
            const rollInterval = setInterval(() => {
                $('#roll-number').text(Math.floor(Math.random() * 20) + 1);
                ticks++;
                if (ticks > 25) { clearInterval(rollInterval); finalizeRoll(action, mod, diff, rollType); }
            }, 40);
        }

        function finalizeRoll(action, mod, diff, rollType) {
            const r1 = Math.floor(Math.random() * 20) + 1;
            const r2 = Math.floor(Math.random() * 20) + 1;
            let finalRoll = r1; let rollStr = `[${r1}]`; let typeStr = ""; let detailText = "";

            if (rollType === 'adv') { finalRoll = Math.max(r1, r2); rollStr = `[${r1}, ${r2}] 优选: ${finalRoll}`; typeStr = "[优势] "; detailText = `( 投掷: ${r1} 与 ${r2} ) 取高`; }
            else if (rollType === 'dis') { finalRoll = Math.min(r1, r2); rollStr = `[${r1}, ${r2}] 劣选: ${finalRoll}`; typeStr = "[劣势] "; detailText = `( 投掷: ${r1} 与 ${r2} ) 取低`; }

            let totalValue = finalRoll + mod;
            let resultText = '', emoji = '', $num = $('#roll-number');

            if (finalRoll === 1) { resultText = '【厄运降临·大失败】'; emoji = '💀'; $num.css('color', '#ff2a2a'); }
            else if (finalRoll === 20) { resultText = '【奇迹生还·大成功】'; emoji = '🌟'; $num.css('color', '#ffcc00'); }
            else if (totalValue >= diff) { resultText = '【检定通过】'; emoji = '✅'; $num.css('color', '#00f0ff'); }
            else { resultText = '【检定失败】'; emoji = '❌'; $num.css('color', '#707080'); }

            $num.text(finalRoll); $('#roll-detail').text(detailText);

            setTimeout(() => {
                const modStr = mod >= 0 ? `+${mod}` : `${mod}`;
                const msg = `【主神系统提示】\n轮回者发起行为：[ ${action} ]\n难度(DC)：${diff}\n🎲 命运投掷(D20${modStr}) ${typeStr}：${rollStr} ${modStr} = 最终结果 ${totalValue}\n系统判定：${emoji} ${resultText}`;

                if (typeof triggerSlash === 'function') triggerSlash(`/send ${msg} | /trigger`);
                else try { const $ta = parent.$('#send_textarea'); if ($ta.length) { $ta.val(msg); $ta[0].dispatchEvent(new Event('input', {bubbles:true})); setTimeout(() => parent.$('#send_but').click(), 100); } } catch (e) {}

                $('#dice-display').removeClass('active'); $('#roll-btn').prop('disabled', false); $('#dice-action').val(''); $num.css('color', '');
                $('input[value="norm"]').prop('checked', true);
            }, 1200);
        }

        async function init() {
            $('.tab-btn').on('click', function() {
                $('.tab-btn').removeClass('active'); $(this).addClass('active');
                $('.tab-content').removeClass('active'); $('#' + $(this).data('tab')).addClass('active');
            });
            $('#dice-action, #dice-mod, #dice-diff').on('click', e => e.stopPropagation());

            initAudioPlayer();

            await waitGlobalInitialized('Mvu');
            populateCharacterData();
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateCharacterData);
        }
        $(errorCatched(init));
    </script>
</head>
