    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const sourceData = document.getElementById('source-data');
            const container = document.getElementById('options-box');

            if (!sourceData || !container) return;

            const textLines = sourceData.innerHTML.trim().split('\n');
            container.innerHTML = '';

            let currentOpt = null;
            const parsedOptions = [];

            textLines.forEach(line => {
                const tl = line.trim();
                if (!tl || tl.includes('【请轮回者做出抉择】')) return;

                if (tl.startsWith('▶')) {
                    if (currentOpt) parsedOptions.push(currentOpt);
                    let titleStr = tl.replace(/^▶\s*/, '');
                    let actionStr = titleStr;
                    const match = titleStr.match(/^(?:选项[A-Z]?|自由行动)[：:]\s*(.*)/);
                    if (match) actionStr = match[1];

                    currentOpt = { title: titleStr, action: actionStr, req: '', dc: '', risk: '' };
                } else if (currentOpt) {
                    if (tl.includes('检定要求')) currentOpt.req = tl.replace(/^-?\s*检定要求[：:]?\s*/, '');
                    else if (tl.includes('难度(DC)')) currentOpt.dc = tl.replace(/^-?\s*难度\(DC\)[：:]?\s*/, '');
                    else if (tl.includes('风险预估')) currentOpt.risk = tl.replace(/^-?\s*风险预估[：:]?\s*/, '');
                }
            });
            if (currentOpt) parsedOptions.push(currentOpt);

            parsedOptions.forEach(opt => {
                const card = document.createElement('div');
                card.className = 'action-card';

                const titleDiv = document.createElement('div');
                titleDiv.className = 'card-title';
                titleDiv.textContent = '> ' + opt.title;
                card.appendChild(titleDiv);

                if (opt.req || opt.dc || opt.risk) {
                    const detailsDiv = document.createElement('div');
                    detailsDiv.className = 'card-details';

                    if (opt.req) detailsDiv.innerHTML += `<div class="detail-row"><span class="detail-label">检定:</span><span>${opt.req}</span></div>`;
                    if (opt.dc) detailsDiv.innerHTML += `<div class="detail-row"><span class="detail-label">DC:</span><span class="dc-badge">${opt.dc}</span></div>`;
                    if (opt.risk) detailsDiv.innerHTML += `<div class="detail-row"><span class="detail-label">风险:</span><span class="risk-text">${opt.risk}</span></div>`;

                    card.appendChild(detailsDiv);
                }

                // 修改后的点击事件：写入剪贴板
                card.addEventListener('click', async (event) => {
                    event.stopPropagation();
                    let textToAppend = opt.action.replace(/\(.*?\)/g, '').replace(/（.*?）/g, '').replace(/\[.*?\]/g, '').trim();

                    // 1. 尝试复制到剪贴板
                    try {
                        await navigator.clipboard.writeText(textToAppend);

                        // 视觉反馈：变为绿色，提示已复制
                        const originalText = titleDiv.textContent;
                        card.classList.add('copied');
                        titleDiv.textContent = '[ ✔ 已复制到剪贴板，请前往输入框粘贴 ]';
                        titleDiv.style.color = 'var(--success-green)';

                        setTimeout(() => {
                            card.classList.remove('copied');
                            titleDiv.textContent = originalText;
                            titleDiv.style.color = '';
                        }, 2000);

                    } catch (error) {
                        console.error('剪贴板复制失败:', error);
                        // 如果浏览器阻止了剪贴板，降级方案：强制塞入输入框
                        try {
                            const input = window.parent.document.querySelector('#send_textarea');
                            if (input) {
                                const currentValue = input.value.trim();
                                input.value = currentValue ? `${currentValue}\n${textToAppend}` : textToAppend;
                                input.dispatchEvent(new Event('input', { bubbles: true }));
                                titleDiv.textContent = '[ ✔ 已填入输入框 ]';
                                setTimeout(() => { titleDiv.textContent = '> ' + opt.title; }, 1500);
                            }
                        } catch (e) {}
                    }

                    document.querySelectorAll('.action-card').forEach(b => b.classList.remove('active'));
                    card.classList.add('active');
                });

                container.appendChild(card);
            });
        });

        const detailsElement = document.querySelector('.fate-choice-terminal');
        const toggleButton = document.getElementById('toggle-text');
        if (detailsElement && toggleButton) {
            detailsElement.addEventListener('toggle', () => {
                toggleButton.textContent = detailsElement.open ? '[ 隐藏控制台 ]' : '[ 展开抉择指令 ]';
            });
        }
    </script>
</body>
</html>
